	function getContractItemAttr(contractItem, attr) {		
		var query = 'u_contract_item=' + contractItem + '^u_attribute=' + attr;
		var grCI = new GlideRecord('sn_customerservice_contract_item_attributes');
		grCI.addEncodedQuery(query);
		grCI.query();
		if (grCI.next()) {
			return grCI.getValue('u_value');
		}
	}

	function getProducts() {
		var gr = new GlideRecord('sys_choice');
		gr.addEncodedQuery('name=u_managed_service_report^element=u_product^inactive=false');
		gr.query();
		var choices = [];
		while(gr.next()) {
			var partNo = gr.getValue('value');
			var moduleName = '';
			if (partNo.includes('MPC')) {
				moduleName = 'EQIX_ManagedPrivateCloud';
			} else if (partNo.includes('MPB')) {
				moduleName = 'EQIX_ManagedPrivateBackup';
			} else if (partNo.includes('MPS')) {
				moduleName = 'EQIX_ManagedPrivateStorage';
			}
			if (!siCustomerPermission.hasPermission('view', moduleName, account)) {
				continue;
			}
			choices.push({
				label: gr.getValue('label'),
				value: gr.getValue('value'),
				// disabled: !siGlobalProducts.hasContract(gr.getValue('value'), orgId),
			});
		}
		return choices;
	}

	function getFormats() {
		var gr = new GlideRecord('sys_choice');
		gr.addEncodedQuery('name=u_managed_service_report^element=u_format^inactive=false');
		gr.query();
		var choices = [];
		while(gr.next()) {
			choices.push({
				label: gr.getValue('label'),
				value: gr.getValue('value')
			});
		}
		return choices;
	}

	function normalizeValue(value)
	{
		if (!value) return '';
		if (value === 'undefined' || value === 'null') return '';
		return value;
	}

    function optCopy(names) {
        names.forEach(function(name) {
            data[name] = input[name] !== undefined ? input[name] : options[name];
        });
    }
})();
